    if not args or len(args) < 2:
        return "Invalid input"

    action = args[0]
    user_id = args[1]

    if action == "add_sso_login":
        return add_sso_login(user_id)
    elif action == "remove_sso_login":
        return remove_sso_login(user_id)
    else:
        return "Unknown action"

def add_sso_login(user_id):
    # Logic to add SSO login for the user
    return f"SSO login added for user {user_id}"

def remove_sso_login(user_id):
    # Logic to remove SSO login for the user
    return f"SSO login removed for user {user_id}"
